import{_ as e,a as t,M as o,o as l}from"./chunks/framework.BzjwFSRk.js";const i="/assets/NHPSVSvez1M.C-fmR-1R.jpeg",r="/assets/ti_psrCTvHo.DL91s5j_.jpeg",b=JSON.parse('{"title":"Первая кузня","description":"","frontmatter":{"title":"Первая кузня","date":"2019-05-12","icon":"11249764_500.png","cover":"cover.jpeg","youtube":"https://youtu.be/o6MH-fb6234","status":"open","url":"https://1кузня.рф","address":"Большая Новодмитровская д.36, стр.26","place":"Флакон","city":"г. Москва","tel":"+7 (495) 120-12-16","email":"pkuznya@gmail.com","instagram":"1kuznya","vk":"1kuznya","facebook":"1kuznya","youtube-channel":"UC7GXAlw-km0TsbUYUKjNcXQ","coord":[55.80563098438347,37.58622425417191]},"headers":[],"relativePath":"workshop/catalog/1kuznya/index.md","filePath":"workshop/catalog/1kuznya/index.md"}'),n={name:"workshop/catalog/1kuznya/index.md"};function s(p,a,h,c,u,d){return l(),t("div",null,[...a[0]||(a[0]=[o('<h3 id="о-кузне-на-флаконе" tabindex="-1">О кузне на Флаконе <a class="header-anchor" href="#о-кузне-на-флаконе" aria-label="Permalink to &quot;О кузне на Флаконе&quot;">​</a></h3><p>Первая Кузня — кузница в Москве для всех, кто хочет покорить стихию огня и выразить своё настроение и идеи в металле. На мастер-классах Первой Кузни Вы куёте самостоятельно, с помощью и советом опытных мастеров. В пространстве Первой кузни, остаётся у Вас в конце занятия!</p><p>Мы находимся в очень творческом месте в центре Москвы — в секторе ремёсел дизайн-завода Flacon. Для глубокого экскурса в древнее ремесло ковки кузница оборудована аутентичным угольным горном прямо в центре, а ковка проходит вручную на старинных наковальнях. Наши мастера преданы делу и умеют найти индивидуальный подход к каждому посетителю!</p><p>Пространство кузни работает и как открытая мастерская, то есть существует почасовая аренда. Ждём Вас в Первой Кузне!</p><h4 id="молоты-в-руки-присоединяися" tabindex="-1">Молоты в руки! Присоединяйся! <a class="header-anchor" href="#молоты-в-руки-присоединяися" aria-label="Permalink to &quot;Молоты в руки! Присоединяйся!&quot;">​</a></h4><p><img src="'+i+'" alt=""></p><h5 id="удачное-расположение" tabindex="-1">Удачное расположение <a class="header-anchor" href="#удачное-расположение" aria-label="Permalink to &quot;Удачное расположение&quot;">​</a></h5><p>Первая Кузня расположена на дизайн-заводе Флакон. Вся территория — один большой интерактивный арт-объект в центре Москвы. Пешая доступность от м. Дмитровская и м. Савёловская. Удобная парковка на территории дизайн-завода.</p><h5 id="радуем-глаз-и-сердце" tabindex="-1">Радуем глаз и сердце <a class="header-anchor" href="#радуем-глаз-и-сердце" aria-label="Permalink to &quot;Радуем глаз и сердце&quot;">​</a></h5><p>Каждое ваше посещение Первой Кузни наполнено атмосферой творчества и вдохновения. Мы сделали всё, чтобы у Вас оставались самые приятные воспоминания о своём опыте ручной ковки. Наши посетители работают с оригинальным угольным горном, в старинном интерьере традиционной кузнечной мастерской.</p><h5 id="активныи-отдых" tabindex="-1">Активный отдых <a class="header-anchor" href="#активныи-отдых" aria-label="Permalink to &quot;Активный отдых&quot;">​</a></h5><p>Хорошая физическая подготовка не требуется. Занятия для всех, кому уже есть 6 лет. Развитие физической силы и закалка воли — крутой бонус от занятий ковкой!</p><h5 id="много-практики" tabindex="-1">Много практики <a class="header-anchor" href="#много-практики" aria-label="Permalink to &quot;Много практики&quot;">​</a></h5><p>95% времени обучения отдаётся практическим занятиям, в конце занятия у Вас в руках выкованное Вами изделие! Вы начинаете работу с обыкновенной металлической заготовки и уходите с готовым изделием!</p><h5 id="у-нас-можно" tabindex="-1">У нас можно! <a class="header-anchor" href="#у-нас-можно" aria-label="Permalink to &quot;У нас можно!&quot;">​</a></h5><p>Фотографируйтесь, делайте селфи и не забывайте отмечать нас хэштегом #1кузня 😃 А ещё приводите друзей и семью посмотреть — это бесплатно!</p><h5 id="скидки-и-программы-лояльности" tabindex="-1">Скидки и программы лояльности <a class="header-anchor" href="#скидки-и-программы-лояльности" aria-label="Permalink to &quot;Скидки и программы лояльности&quot;">​</a></h5><p>Для многодетных семей, людей с ограниченными возможностями здоровья и других категорий граждан.</p><p><img src="'+r+'" alt=""></p><h3 id="аренда-кузни" tabindex="-1">Аренда кузни <a class="header-anchor" href="#аренда-кузни" aria-label="Permalink to &quot;Аренда кузни&quot;">​</a></h3><p>&quot;Первая Кузня&quot; — это обучающее и рабочее пространство для начинающих и опытных кузнецов и художников по металлу. К нам приходят как люди без опыта, чтобы впервые познакомиться с кузнечным делом, так и опытные мастера, чтобы тренироваться, нарабатывать портфолио, выполнять небольшие заказы.</p><p>Посещая Первую Кузню для аренды, Вы получаете возможность изготавливать изделия в комфортной обстановке красивой и хорошо оборудованной мастерской.</p><p>Аренда включает:</p><ul><li>✓ Твердотопливный горн с автоподдувом</li><li>✓ Кузнечный инструмент</li><li>✓ Наковальни</li><li>✓ Спецодежда (спилковые фартуки, нарукавники, текстильные перчатки)</li><li>✓ Защита (пластиковые очки)</li><li>✓ Заготовки сталь-3 или арматура</li><li>✓ Техническая поддержка персонала кузни (помощь в поддержании огня в горне, помощь в подборе инструмента и т. п.)</li></ul><p>Внимание! Обязательное требование техники безопасности в кузнице! Если Вы собираетесь использовать кузнечное оборудование, но не имеете необходимой квалификации, Вам необходимо сначала выполнить одно из следующих условий:</p><ul><li>Наличие подтверждённого опыта работы в сфере кузнечной ковки, не менее 3 месяцев;</li><li>Наличие свидетельства об обучении на курсах кузнечного ремесла в любой из отечественных или зарубежных школ;</li><li>Членство в клубе Первой Кузни (5 посещений любых мастер-классов, либо прохождение курса &quot;Базовые техники ковки&quot; или курса &quot;Кузнец-оружейник&quot;).</li></ul>',26)])])}const k=e(n,[["render",s]]);export{b as __pageData,k as default};
